INSERT INTO materials (id, slug, title, short_description, full_description, access_type, category_id, age_group, file_type, price, cover_url, preview_text, preview_file_url, paid_file_url, is_published, is_featured, seo_title, seo_description, program, what_is_included, created_at, updated_at) VALUES ('b9cfd3c3-2243-5262-ae5e-3788bff7fa0b', 'kviz-moya-rodina-rossiya', 'Квиз Моя Родина Россия', 'Познавательный квиз о России для детей дошкольного возраста.', 'Готовый квиз для проведения познавательного мероприятия о России. Включает вопросы о природе, городах, символах и культуре страны. Подходит для подготовительной и старшей групп.', 'store', '51328737-34c9-572d-b212-6b48b4560c1c', '5–7 лет', 'PDF', 45000, '', 'Познавательный квиз о России для детей дошкольного возраста.', '', '', true, false, 'Квиз Моя Родина Россия — скачать для детского сада', 'Познавательный квиз о России для детей дошкольного возраста.', 'Универсальный', '{"Список вопросов с ответами","Карточки с заданиями","Правила проведения квиза","Грамоты участников"}', now(), now()) ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, short_description = EXCLUDED.short_description, full_description = EXCLUDED.full_description, access_type = EXCLUDED.access_type, category_id = EXCLUDED.category_id, age_group = EXCLUDED.age_group, file_type = EXCLUDED.file_type, price = EXCLUDED.price, seo_title = EXCLUDED.seo_title, seo_description = EXCLUDED.seo_description, program = EXCLUDED.program, what_is_included = EXCLUDED.what_is_included, updated_at = now();
INSERT INTO materials (id, slug, title, short_description, full_description, access_type, category_id, age_group, file_type, price, cover_url, preview_text, preview_file_url, paid_file_url, is_published, is_featured, seo_title, seo_description, program, what_is_included, created_at, updated_at) VALUES ('6bdcdec5-11db-5893-b834-4db98fb6a21b', 'pedsover-edinstvo-narodov-rossii', 'Педсовет / семинар Единство народов России', 'Методический материал для педагогического совета о единстве народов России.', 'Полностью готовый материал для проведения педагогического совета или семинара по теме «Единство народов России». Включает план проведения, презентацию и раздаточные материалы для участников.', 'store', 'f4ccdc89-846c-52cb-86d9-7d26044b8c3a', 'Педагоги', 'PPTX', 100000, '', 'Методический материал для педагогического совета о единстве народов России.', '', '', true, false, 'Педсовет / семинар Единство народов России — скачать для детского сада', 'Методический материал для педагогического совета о единстве народов России.', 'Универсальный', '{"Сценарий педсовета","Презентация","Раздаточный материал","Протокол"}', now(), now()) ON CONFLICT (slug) DO UPDATE SET title = EXCLUDED.title, short_description = EXCLUDED.short_description, full_description = EXCLUDED.full_description, access_type = EXCLUDED.access_type, category_id = EXCLUDED.category_id, age_group = EXCLUDED.age_group, file_type = EXCLUDED.file_type, price = EXCLUDED.price, seo_title = EXCLUDED.seo_title, seo_description = EXCLUDED.seo_description, program = EXCLUDED.program, what_is_included = EXCLUDED.what_is_included, updated_at = now();
